131	vnf_p7_rx_message_t* vnf_p7_rx_reassembly_queue_add_segment(vnf_p7_t* vnf_p7, vnf_p7_rx_reassembly_queue_t* queue, uint16_t sequence_number, uint16_t segment_number, uint8_t m, uint8_t* data, uint16_t data_len)
132	{
133		vnf_p7_rx_message_t* msg = 0;
134		// attempt to find a entry for this segment
135		vnf_p7_rx_message_t* iterator = queue->msg_queue;
136		while(iterator != 0)
137		{
138			if(iterator->sequence_number == sequence_number)
139			{
140				msg = iterator;
141				break;
142			}
143	
144			iterator = iterator->next;
145		}
146		
147		// if found then copy data to message
148		if(msg != 0)
149		{
150		
151			msg->segments[segment_number].buffer = (uint8_t*)vnf_p7_malloc(vnf_p7, data_len);
152			memcpy(msg->segments[segment_number].buffer, data, data_len);
153			msg->segments[segment_number].length = data_len;
154	
155			msg->num_segments_received++;
156	
157			// set the segement number if we have the last segment
158			if(m == 0)
159				msg->num_segments_expected = segment_number + 1;
160		}
161		// else add new rx message entry
162		else
163		{
164			// create a new message
165			msg = (vnf_p7_rx_message_t*)(vnf_p7_malloc(vnf_p7, sizeof(vnf_p7_rx_message_t)));
166			memset(msg, 0, sizeof(vnf_p7_rx_message_t));
167	
168			msg->sequence_number = sequence_number;
169			msg->num_segments_expected = m ? 255 : segment_number + 1;
170			msg->num_segments_received = 1;
171			msg->rx_hr_time = vnf_get_current_time_hr();
172	
173			msg->segments[segment_number].buffer = (uint8_t*)vnf_p7_malloc(vnf_p7, data_len);
174			memcpy(msg->segments[segment_number].buffer, data, data_len);
175			msg->segments[segment_number].length = data_len;
176	
177			// place the message at the head of the queue
178			msg->next = queue->msg_queue;
179			queue->msg_queue = msg;
180		}
181	
182		return msg;
183	}
